{
  "name": "Program of All-Inclusive Care for the Elderly (PACE) - Not available in MS",
  "eligibility": {
    "age": 55,
    "income_limits": "No income limits; no financial criteria considered for eligibility[1][4][5]",
    "asset_limits": "No asset limits; financial status does not affect eligibility[1][4]",
    "other_requirements": [
      "Live in the service area of a PACE organization (none in Mississippi)",
      "Certified by the state as needing nursing home level of care",
      "Able to live safely in the community with PACE services",
      "Not enrolled in Medicare Advantage, Medicare prepayment plan, Medicare prescription drug plan, or hospice[1][5]"
    ]
  },
  "benefits": {
    "type": "service",
    "value": "Comprehensive services including adult day care, transportation, primary medical care, in-home/outpatient therapy, meals/nutrition, prescription drugs, and all Medicare/Medicaid-covered services without copays/deductibles for enrollees[2][4]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": [],
    "processing_time": null,
    "waitlist": "Waitlists common where available, but irrelevant in MS[3]",
    "forms": [],
    "documents": []
  },
  "geography": {
    "statewide": false,
    "restrictions": "Not available in Mississippi; as of June 2025, 33 states + DC have PACE, MS not included[4]",
    "regional_variations": null,
    "offices_or_providers": []
  },
  "official_source": "https://www.medicare.gov/health-drug-plans/health-plans/your-coverage-options/other-medicare-health-plans/PACE[5]",
  "gotchas": [
    "PACE is unavailable in Mississippi, so families cannot enroll regardless of meeting other criteria[4]",
    "Must live in a PACE service area, which excludes all of MS[1][3][5]",
    "Even if eligible elsewhere, cannot be in Medicare Advantage or hospice[1]",
    "Non-Medicaid enrollees may pay premiums for long-term care and Part D drugs[3][7]"
  ],
  "data_shape_notes": "Not available in Mississippi; no providers, no service areas, no applications possible; eligibility hinges on geographic availability which MS lacks"
}

{
  "name": "Mississippi SHIP (State Health Insurance Assistance Program)",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; open to all Medicare beneficiaries, their families, caregivers, and representatives of disabled persons[1][2][3]",
    "asset_limits": "No asset limits or tests apply[1][2]",
    "other_requirements": ["Must be a Medicare beneficiary, disabled person, or inquiry on their behalf; no other restrictions[1][2][3]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free one-on-one counseling on Medicare Parts A/B/C/D, Medigap, Medicare Savings Programs, Extra Help/LIS, Medicaid, long-term care options, SenioRxMS, appeals, claims, bill organization, fraud prevention via SMP; outreach events, presentations, printed materials, referrals[1][2][3][6]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 1-844-822-4622 or 601-709-0624 (M-F 8am-5pm)[3][8]", "Website: https://www.mdhs.ms.gov/adults-seniors/services-for-seniors/state-health-insurance-assistance-program/[3]", "In-person and phone-based counseling available statewide[3]"],
    "processing_time": "Immediate assistance via phone or in-person; no formal application processing[3]",
    "waitlist": null,
    "forms": ["No specific forms required; contact for counseling[1][7]"],
    "documents": ["No documents needed for initial counseling; may require Medicare info, bills, or plan details for specific help[3][6][7]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available to all Mississippi Medicare beneficiaries[1][3][4]",
    "regional_variations": "Uniform statewide administration through MDHS Division of Aging and Adult Services; local counseling via network but no specified differences in services, wait times, or providers by region[1][3][4]",
    "offices_or_providers": ["Main office: Mississippi Department of Human Services, 750 North State Street, Jackson MS 39202[4]"]
  },
  "official_source": "https://www.mdhs.ms.gov/adults-seniors/services-for-seniors/state-health-insurance-assistance-program/",
  "gotchas": ["Not a financial aid or healthcare provider program—only free counseling and education, no direct payments or services; distinguish from Small Rural Hospital Improvement (SHIP) grant which is unrelated[5]; services are unbiased and objective, not sales-oriented; counselors must be CMS-trained annually[1][2][3]"],
  "data_shape_notes": "no income/asset/age test; purely counseling service with statewide phone/in-person access; funded by federal grants to MDHS, volunteer/staff network"
}

{
  "name": "Mississippi Meals on Wheels (via Aging and Disability Resource Centers)",
  "eligibility": {
    "age": 60,
    "income_limits": "No income limits or means testing; program is not income-based[2].",
    "asset_limits": "No asset limits or means testing[2].",
    "other_requirements": ["Homebound or unable to shop for food, prepare meals, or socialize due to mobility challenges[1][5][6]", "Potentially at risk for early institutionalization[6]", "Priority to those on no congregate meals waiting list; spouses of eligible adults may qualify regardless of age[2][5]", "Nutrition risk assessment via Consumer Information Form (CIF)[2]"]
  },
  "benefits": {
    "type": "service",
    "value": "Minimum five frozen meals per week, each providing at least 33 1/3% of dietary reference intakes (DRIs); may include hot noon meals 5 days/week in some areas[2][4][6]. Meals meet Older Americans Act nutrition standards[2]. Suggested donation or sliding scale possible, but voluntary contributions only[1][2].",
    "varies_by": "region"
  },
  "application": {
    "methods": ["Contact local Aging and Disability Resource Center (ADRC) or Area Agency on Aging via MDHS search tool at https://www.mdhs.ms.gov/aging/services/[6]", "Phone examples: 662-844-1441 ext. 1056 for Lee County (Mississippi Methodist Senior Services)[4]", "Application and needs assessment required; possible doctor/social worker referral[1]"],
    "processing_time": "Not specified in sources",
    "waitlist": "Priority access if no one on home-delivered waiting list; waitlists exist and may limit availability[2]",
    "forms": ["Nutrition Risk Assessment via Consumer Information Form (CIF) or state client tracking system[2]"],
    "documents": ["Application form, possible referral letter from doctor or social worker[1]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Available through local providers and Area Agencies on Aging; varies by county availability[1][4][6]",
    "regional_variations": "Delivery type (frozen vs. hot), frequency, and providers differ by region (e.g., 5 hot meals/week in Lee County via Mississippi Methodist Senior Services; minimum 5 frozen statewide)[2][4][6]. Use local ADRC search for specifics[6].",
    "offices_or_providers": ["Local Area Agencies on Aging/ADRCs statewide; example: Mississippi Methodist Senior Services, 2800 West Main St., Tupelo, MS 38801 for Lee County[4][6]"]
  },
  "official_source": "https://www.mdhs.ms.gov/aging/services/",
  "gotchas": ["Not means-tested, but priority to homebound 60+ with no congregate options; meals may be frozen (min 5/week) not always hot/fresh[2][6]", "Availability limited by waitlists and local providers; contact ADRC first, not national Meals on Wheels[1][2][6]", "Spouses under 60 may qualify if linked to eligible adult, but under-60 generally only with disabilities[5]", "Voluntary contributions expected but not required; private options like Mom's Meals ($9.49/meal) if ineligible[3]"],
  "data_shape_notes": "Administered statewide via local Area Agencies on Aging/ADRCs with no income/asset test; priority-based access with regional provider and meal format variations (frozen minimum vs. hot in some counties)"
}

{
  "name": "Mississippi Family Caregiver Support Program",
  "eligibility": {
    "age": null,
    "income_limits": "Priority given to low-income older individuals with greatest social and economic need; no specific dollar amounts or household size table provided in sources[5][6].",
    "asset_limits": "No asset limits specified[6].",
    "other_requirements": [
      "Caregivers: Adults age 18+ caring for eligible care recipients; special populations include adults 55+ caring for non-child adults 18+ with developmental disabilities, or grandparents/relatives 60+ caring for children 18 or younger[3][5][6].",
      "Care recipients: Older adults (typically 60+) or people with disabilities; also children under 18 for relative caregivers 60+[6].",
      "Priority to older individuals with greatest social/economic need, low-income, and those caring for persons with mental retardation/related developmental disabilities[5]."
    ]
  },
  "benefits": {
    "type": "service",
    "value": "Five core services: 1) Information about available services; 2) Assistance gaining access to services; 3) Individual counseling, support groups, caregiver training; 4) Respite care (one unit = one hour); 5) Supplemental services on limited basis to complement care. No fixed dollar amounts or weekly hours specified beyond respite unit definition[5][6][7].",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": [
      "Phone: Contact Mississippi Access to Care (MAC) Center at 844-822-4622[6].",
      "Partnerships: Through community-based Area Agencies on Aging (AAA) and local providers[6]."
    ],
    "processing_time": "Not specified in sources.",
    "waitlist": null,
    "forms": [],
    "documents": ["Not specified; prepare proof of relationship, care needs, and any disability documentation as assessed by providers[6]."]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None specified; delivered statewide via local AAAs and providers[6].",
    "regional_variations": "Administered through local community service providers and AAAs, potentially varying by provider availability or wait times, but no specific differences detailed[6].",
    "offices_or_providers": ["Area Agencies on Aging (AAA), local community providers; contact via MAC Center[6]."]
  },
  "official_source": "https://www.mdhs.ms.gov/aging/caregivers/[6]",
  "gotchas": [
    "Not a paid caregiving program (no direct payments to family caregivers); focuses on support services like respite and counseling[6].",
    "Often confused with Medicaid EDWP (pays family caregivers) or VA PCAFC (veteran-specific)[1][4].",
    "Priority-based access may limit availability for non-priority caregivers[5].",
    "Separate from Mississippi Dementia Care Program, which provides ~27 hours/month respite for ADRD caregivers[6]."
  ],
  "data_shape_notes": "Services delivered via local AAAs/providers with priority tiers for low-income/greatest need; no strict income/asset tests or fixed benefits; not payment-based"
}

{
  "name": "Senior Community Service Employment Program (SCSEP) - Mississippi",
  "eligibility": {
    "age": 55,
    "income_limits": "Family income at or below 125% of the federal poverty level, determined by size of family unit per HHS poverty guidelines (2025 guidelines effective January 15, 2025; contact local office for current table as exact dollar amounts not specified in sources)[1][2][3]",
    "asset_limits": "No asset limits mentioned[1][2][3]",
    "other_requirements": ["Unemployed", "Mississippi resident", "Few employment prospects", "U.S. citizen or authorized to work in U.S.", "If male, meet U.S. Military Selective Service registration requirements", "Priority for veterans, qualified spouses, and those with 'most in need' characteristics"][2][3][4]
  },
  "benefits": {
    "type": "employment",
    "value": "Part-time subsidized community service work experience (average 20 hours/week) at non-profit/government host agencies; training in skills for roles like child care, customer service, teachers' aide, computer technician, building maintenance, health care; pay at highest of federal/state/local minimum wage; typically 6 months training before job placement assistance[1][2][6]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Contact local SCSEP office via Mississippi Department of Employment Security (MDES) (no specific statewide phone listed; email GWood@mdes.ms.gov for waiver info)", "In-person or mail application through local providers like area agencies on aging, non-profits (e.g., Copiah-Lincoln Community College, SMPDD)", "Programs administered in all 82 counties; find local office through MDES site http://mdes.ms.gov/i-need-a-job/senior-employment-program/"][2][6]],
    "processing_time": "If eligible and no waiting list, enrolled immediately; no specific statewide timeline given[1]",
    "waitlist": "Possible waiting list depending on local availability[1]",
    "forms": ["Complete an application at local SCSEP office; no specific form name/number listed"],
    "documents": ["Eligibility documentation (income proof, age, residency, employment status, citizenship/work authorization, Selective Service if applicable); maintain confidential files"][3]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Available in all 82 counties; Mississippi residents only[2]",
    "regional_variations": "Administered by MDES through varying local providers (area agencies on aging, non-profits like Copiah-Lincoln Community College, SMPDD); potential differences in wait times, availability, offices by county/region[2][5][6]",
    "offices_or_providers": ["Mississippi Department of Employment Security (MDES)", "Area agencies on aging", "Non-profit organizations (e.g., Copiah-Lincoln Community College, South Mississippi Planning and Development District (SMPDD))"][2][3][5][6]
  },
  "official_source": "http://mdes.ms.gov/i-need-a-job/senior-employment-program/",
  "gotchas": ["Priority service for veterans/qualified spouses and 'most in need' must be ensured[3][4]", "Eligibility determined and documented before any services[3]", "Limited duration (typically 6 months) focused on transition to unsubsidized employment, not long-term[1][2]", "Income based on 125% poverty level by family size—verify current HHS table[2][3]", "Potential waitlists vary locally[1]", "Funded under Title V Older Americans Act; subject to federal DOL rules and state waivers[2][3]"],
  "data_shape_notes": "Administered statewide via 82 counties with multiple local non-profit/area agency providers; income test at 125% poverty by family size; priority tiers for veterans/most in need; no fixed asset limits or statewide processing times"
}

{
  "name": "Mississippi Legal Services (Senior Legal Helpline)",
  "eligibility": {
    "age": 60,
    "income_limits": "Household gross income at or below 125% of federal poverty guidelines. Exact dollar amounts vary annually by household size (based on HHS federal poverty guidelines); exceptions possible for seniors. Total receipts include wages, salaries before deductions, and regular public assistance payments (e.g., Social Security, SSI, TANF) from all resident household members contributing to support.[1][2][3][5]",
    "asset_limits": "No asset limits mentioned in available sources.",
    "other_requirements": ["Reside in service area (central/southern Mississippi for MCLSC or northern for NMRLS)", "Not prisoners", "Civil legal issues only (e.g., consumer, housing, family, elder care)"]
  },
  "benefits": {
    "type": "service",
    "value": "Free civil legal assistance including phone advice, document review, letter writing, advocacy, and representation in areas like elder care, housing, family, consumer, income maintenance. No attorney fees charged. Limited to phone advice in some cases with possible referrals.[1][3][4][5][8]",
    "varies_by": "region"
  },
  "application": {
    "methods": [
      "Phone: MCLSC (central/southern MS) 1-800-519-2915 or 1-800-498-1804; NMRLS (north MS) 1-800-898-8731",
      "Website: mscenterforlegalservices.org (apply online), mslegalservices.org (intake guide)",
      "In-person: e.g., Jackson Office at 414 South State Street, Third Floor, Jackson, MS 39205"
    ],
    "processing_time": "Not specified in sources.",
    "waitlist": null,
    "forms": ["Online intake form via mscenterforlegalservices.org or mslegalservices.org"],
    "documents": ["Proof of income (e.g., pay stubs, benefit statements), household size details, zip code/county for service area verification"]
  },
  "geography": {
    "statewide": false,
    "restrictions": "Divided by region: North Mississippi (NMRLS), central/southern Mississippi (MCLSC, 43 counties)",
    "regional_variations": "Separate providers (NMRLS vs. MCLSC) with distinct intake hotlines as of January 1, 2026; NMRLS focuses on elder care, domestic violence; MCLSC on consumer, education, housing. Online intake for NMRLS temporarily closed.[5][7][8]",
    "offices_or_providers": ["North Mississippi Rural Legal Services (NMRLS): north MS, nmrls.com", "Mississippi Center for Legal Services (MCLSC): central/southern MS (43 counties), mscenterforlegalservices.org"]
  },
  "official_source": "https://mscenterforlegalservices.org and https://www.mslegalservices.org",
  "gotchas": [
    "Not fully statewide—must use correct regional hotline/provider based on zip code/county (north vs. central/southern MS)",
    "Income is gross household total from all contributing members; seniors may get exceptions but still screened",
    "Excludes prisoners and criminal cases; only civil matters",
    "Online intake for north MS temporarily closed—use phone",
    "Hotline numbers changed January 2026; older numbers (e.g., 888-660-0008) may be outdated"
  ],
  "data_shape_notes": "Regionally divided with separate providers/hotlines; income at 125% FPL with senior exceptions; no asset test or exact dollar tables in sources (varies yearly by household size)"
}

{
  "name": "Mississippi Long-Term Care Ombudsman Program",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; available regardless of ability to pay.",
    "asset_limits": "No asset limits; no financial requirements.",
    "other_requirements": [
      "Resides in or is a potential resident of a long-term care facility subject to regulation or licensure by the Mississippi State Department of Health (e.g., nursing homes, assisted living facilities, personal care homes, adult day care, long-term rehab centers, hospice centers).",
      "Complainants (e.g., family members) can contact on behalf of residents without residency requirement."
    ]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Assists with complaints (abuse, neglect, improper discharge, food quality, medication issues); conducts facility visits and assessments; provides information on rights; helps select facilities; systems advocacy for groups; resolves problems to improve quality of life. In 2023: 973 individuals assisted, 151,094 visits, 2,352 complaints fully resolved.",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": [
      "Phone: 1-888-844-0041 (toll-free) or 601-359-4927 (State Ombudsman Lisa M. Smith)",
      "Website: https://www.mdhs.ms.gov/aging/ombudsman/",
      "Mail: MDHS, 200 South Lamar St., Jackson, MS 39201"
    ],
    "processing_time": "Timely responses to requests and complaints required, but no specific timeline stated.",
    "waitlist": null,
    "forms": [],
    "documents": [
      "No specific documents required; provide details of complaint or issue (facility name, resident info, description of problem)."
    ]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Limited to licensed long-term care facilities across all 82 counties.",
    "regional_variations": "Services provided through contracts with Area Agencies on Aging (AAAs); 19 local ombudsmen (2 staff) cover statewide; each AAA must have at least one designated ombudsman; access ensured via travel funds.",
    "offices_or_providers": ["Delivered via Division of Aging and Adult Services (DAAS) contracts with AAAs; central office in Jackson."]
  },
  "official_source": "https://www.mdhs.ms.gov/aging/ombudsman/",
  "gotchas": [
    "Not a direct service provider (e.g., no personal care, meals, or financial aid); purely advocacy and complaint resolution.",
    "No Medicaid or financial eligibility test—open to all, but only for regulated long-term care facilities.",
    "Family/complainants drive access; residents don't apply independently.",
    "Volunteers must be certified; public contacts staff or designated ombudsmen.",
    "Not for community/home-based care—facility-focused only."
  ],
  "data_shape_notes": "No income/asset/age tests; advocacy-only (non-financial); delivered via 19 local ombudsmen through AAAs covering all counties; complaint-driven access."
}

