    "methods": ["Website: https://www.mississippiaccesstocare.org (primary entry point for info/programs)", "Phone: Not specified in results; contact Mississippi Division of Medicaid at general line or local Area Agency on Aging (search medicaid.ms.gov)", "Mail/In-person: Apply via Mississippi Medicaid at medicaid.ms.gov or local offices; Pre-Admission Screening via eLTSS system"],
    "processing_time": "Not specified",
    "waitlist": "Likely due to waiver slots (common for HCBS); not detailed",
    "forms": ["Long Term Services and Supports (LTSS) assessment tool for NFLOC; Medicaid application via medicaid.ms.gov"],
