  "geography": {
    "statewide": true,
    "restrictions": "Statewide for eligible Mississippi residents",
    "regional_variations": "Delivered via local providers/Area Agencies on Aging; potential differences in wait times/providers by region, but not detailed",
    "offices_or_providers": ["Local long-term care providers; contact via mississippiaccesstocare.org"]
  },
  "official_source": "https://www.mississippiaccesstocare.org",
  "gotchas": ["Must first qualify for Medicaid ABD (people miss the strict NFLOC assessment—not just age/disability)", "Home equity limit $752,000 excludes many with home ownership", "Waiver has limited slots leading to waitlists", "Must accept all other benefits (e.g., VA/SSI) or lose eligibility", "Dementia diagnosis alone does not guarantee NFLOC"],
  "data_shape_notes": "Tied to Medicaid E&D Waiver; eligibility via Medicaid ABD + NFLOC; services fixed list, no dollar/hour caps specified; statewide but provider-delivered with potential regional wait/provider variations"
